import{_ as a,c as t,o,a1 as n}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"Advanced: AI Workflows | oh-my-opencode","description":"Master advanced AI workflow orchestration in oh-my-opencode. Learn agent teams, parallel tasks, Categories/Skills system, lifecycle hooks, and deep customization to build efficient AI-powered development systems.","frontmatter":{"title":"Advanced: AI Workflows | oh-my-opencode","sidebarTitle":"Work Like a Team","subtitle":"Advanced: AI Workflows","description":"Master advanced AI workflow orchestration in oh-my-opencode. Learn agent teams, parallel tasks, Categories/Skills system, lifecycle hooks, and deep customization to build efficient AI-powered development systems.","order":60},"headers":[],"relativePath":"code-yeongyu/oh-my-opencode/advanced/index.md","filePath":"code-yeongyu/oh-my-opencode/advanced/index.md"}'),i={name:"code-yeongyu/oh-my-opencode/advanced/index.md"};function s(r,e,l,d,c,p){return o(),t("div",null,[...e[0]||(e[0]=[n(`<h1 id="advanced" tabindex="-1">Advanced <a class="header-anchor" href="#advanced" aria-label="Permalink to &quot;Advanced&quot;">​</a></h1><p>This chapter dives deep into the advanced features of oh-my-opencode: professional AI agent teams, parallel background tasks, Categories and Skills system, lifecycle hooks, and more. Mastering these capabilities will enable you to orchestrate AI workflows like managing a real team, achieving a more efficient development experience.</p><h2 id="chapter-content" tabindex="-1">Chapter Content <a class="header-anchor" href="#chapter-content" aria-label="Permalink to &quot;Chapter Content&quot;">​</a></h2><div class="grid-cards"><h3 id="ai-agent-teams-10-experts-overview" tabindex="-1"><a href="./ai-agents-overview/">AI Agent Teams: 10 Experts Overview</a> <a class="header-anchor" href="#ai-agent-teams-10-experts-overview" aria-label="Permalink to &quot;[AI Agent Teams: 10 Experts Overview](./ai-agents-overview/)&quot;">​</a></h3><p>Comprehensive introduction to the functionality, use cases, and calling methods of 10 built-in agents. Learn to select the right agent based on task type, enabling efficient team collaboration, parallel task execution, and deep code analysis.</p><h3 id="prometheus-planning-interview-based-requirements-gathering" tabindex="-1"><a href="./prometheus-planning/">Prometheus Planning: Interview-Based Requirements Gathering</a> <a class="header-anchor" href="#prometheus-planning-interview-based-requirements-gathering" aria-label="Permalink to &quot;[Prometheus Planning: Interview-Based Requirements Gathering](./prometheus-planning/)&quot;">​</a></h3><p>Clarify requirements and generate work plans through interview mode. Prometheus will continue asking questions until requirements are clear, and automatically consults Oracle, Metis, and Momus to verify plan quality.</p><h3 id="background-parallel-tasks-work-like-a-team" tabindex="-1"><a href="./background-tasks/">Background Parallel Tasks: Work Like a Team</a> <a class="header-anchor" href="#background-parallel-tasks-work-like-a-team" aria-label="Permalink to &quot;[Background Parallel Tasks: Work Like a Team](./background-tasks/)&quot;">​</a></h3><p>In-depth explanation of the background agent management system usage. Learn concurrency control, task polling, and result retrieval, enabling multiple AI agents to handle different tasks simultaneously, dramatically improving work efficiency.</p><h3 id="lsp-and-ast-grep-code-refactoring-tools" tabindex="-1"><a href="./lsp-ast-tools/">LSP and AST-Grep: Code Refactoring Tools</a> <a class="header-anchor" href="#lsp-and-ast-grep-code-refactoring-tools" aria-label="Permalink to &quot;[LSP and AST-Grep: Code Refactoring Tools](./lsp-ast-tools/)&quot;">​</a></h3><p>Introduction to the usage of LSP tools and AST-Grep tools. Demonstrate how to implement IDE-level code analysis and operations, including symbol navigation, reference lookup, and structured code search.</p><h3 id="categories-and-skills-dynamic-agent-composition" tabindex="-1"><a href="./categories-skills/">Categories and Skills: Dynamic Agent Composition</a> <a class="header-anchor" href="#categories-and-skills-dynamic-agent-composition" aria-label="Permalink to &quot;[Categories and Skills: Dynamic Agent Composition](./categories-skills/)&quot;">​</a></h3><p>Learn to use the Categories and Skills system to create specialized sub-agents. Implement flexible agent composition, dynamically assigning models, tools, and skills based on task requirements.</p><h3 id="built-in-skills-browser-automation-and-git-expert" tabindex="-1"><a href="./builtin-skills/">Built-in Skills: Browser Automation and Git Expert</a> <a class="header-anchor" href="#built-in-skills-browser-automation-and-git-expert" aria-label="Permalink to &quot;[Built-in Skills: Browser Automation and Git Expert](./builtin-skills/)&quot;">​</a></h3><p>Detailed introduction to the use cases and best practices of three built-in Skills (playwright, frontend-ui-ux, git-master). Quickly access professional capabilities like browser automation, frontend UI design, and Git operations.</p><h3 id="lifecycle-hooks-automated-context-and-quality-control" tabindex="-1"><a href="./lifecycle-hooks/">Lifecycle Hooks: Automated Context and Quality Control</a> <a class="header-anchor" href="#lifecycle-hooks-automated-context-and-quality-control" aria-label="Permalink to &quot;[Lifecycle Hooks: Automated Context and Quality Control](./lifecycle-hooks/)&quot;">​</a></h3><p>Introduction to the usage of 32 lifecycle hooks. Understand how to automate context injection, error recovery, and quality control, building a complete AI workflow automation system.</p><h3 id="slash-commands-preset-workflows" tabindex="-1"><a href="./slash-commands/">Slash Commands: Preset Workflows</a> <a class="header-anchor" href="#slash-commands-preset-workflows" aria-label="Permalink to &quot;[Slash Commands: Preset Workflows](./slash-commands/)&quot;">​</a></h3><p>Introduction to the usage of 6 built-in slash commands. Including /ralph-loop (quick fix loop), /refactor (code refactoring), /start-work (start project execution), and other common workflows.</p><h3 id="configuration-deep-customization-agent-and-permission-management" tabindex="-1"><a href="./advanced-configuration/">Configuration Deep Customization: Agent and Permission Management</a> <a class="header-anchor" href="#configuration-deep-customization-agent-and-permission-management" aria-label="Permalink to &quot;[Configuration Deep Customization: Agent and Permission Management](./advanced-configuration/)&quot;">​</a></h3><p>Teach users deep customization of agent configuration, permission settings, model overrides, and prompt modifications. Master complete configuration capabilities, creating AI workflows that align with team standards.</p></div><h2 id="learning-path" tabindex="-1">Learning Path <a class="header-anchor" href="#learning-path" aria-label="Permalink to &quot;Learning Path&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  Step 1                  Step 2                     Step 3                          Step 4                  │</span></span>
<span class="line"><span>│  Understand AI Agents  →   Master Planning     →   Learn Dynamic Agent     →   Deep Customization      │</span></span>
<span class="line"><span>│  (Basic Concepts)          &amp; Parallel Tasks         Composition                 &amp; Automation             │</span></span>
<span class="line"><span>│                                                      (Advanced Usage)          (Expert Level)           │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────────────────────────────────────────────────────┘</span></span></code></pre></div><p><strong>Recommended Sequence</strong>:</p><ol><li><strong>Start with AI Agent Teams</strong>: Understand the responsibilities and use cases of 10 agents—this is the cornerstone for understanding the entire system.</li><li><strong>Then Learn Planning and Parallel Tasks</strong>: Master Prometheus planning and the background task system—this is the core of efficient collaboration.</li><li><strong>Next Learn Dynamic Agent Composition</strong>: Learn Categories and Skills to achieve flexible agent specialization.</li><li><strong>Finally Learn Deep Customization</strong>: Master lifecycle hooks, slash commands, and configuration customization to build complete workflows.</li></ol><p><strong>Advanced Routes</strong>:</p><ul><li>If your goal is <strong>quick start</strong>: Focus on &quot;AI Agent Teams&quot; and &quot;Slash Commands&quot;</li><li>If your goal is <strong>team collaboration</strong>: Deep dive into &quot;Prometheus Planning&quot; and &quot;Background Parallel Tasks&quot;</li><li>If your goal is <strong>workflow automation</strong>: Learn &quot;Lifecycle Hooks&quot; and &quot;Configuration Deep Customization&quot;</li></ul><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Before You Begin</p><p>This chapter assumes you have completed:</p><ul><li>✅ <a href="./../start/installation/">Quick Installation and Configuration</a>: Installed oh-my-opencode and configured at least one Provider</li><li>✅ <a href="./../start/sisyphus-orchestrator/">First Look at Sisyphus: Main Orchestrator</a>: Understood basic agent calling and delegation mechanisms</li><li>✅ <a href="./../platforms/provider-setup/">Provider Configuration: Claude, OpenAI, Gemini</a>: Configured at least one AI Provider</li></ul></div><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><p>After completing this chapter, we recommend continuing with:</p><ul><li><strong><a href="./../faq/troubleshooting/">Configuration Diagnostics and Troubleshooting</a></strong>: Quickly locate and resolve issues when they arise.</li><li><strong><a href="./../appendix/configuration-reference/">Configuration Reference</a></strong>: View the complete configuration file schema and understand all configuration options.</li><li><strong><a href="./../appendix/claude-code-compatibility/">Claude Code Compatibility</a></strong>: Learn how to migrate existing Claude Code workflows to oh-my-opencode.</li></ul>`,15)])])}const m=a(i,[["render",s]]);export{h as __pageData,m as default};
